final:
module top_module(
  input [n-1:0] in,
  output out
);parameter n = 8; // number of input signals

reg [n-1:0] in_reg;
reg obf_parity;

integer i;
always @(*) begin
  in_reg = in;
  obf_parity = 1'b0;
  for (i = 0; i < n; i = i + 1) begin
    obf_parity = obf_parity ^ in_reg[i];
  end
end

assign out = ~obf_parity;

endmodule
